module padder1(in, byte_num, padded_data);
    input      [31:0] in;
    input      [1:0]  byte_num;
    output reg [31:0] padded_data;
    always @ (*)
      case (byte_num)
        0: padded_data = 32'h1000000;
        1: padded_data = {in[31:24], 24'h010000};
        2: padded_data = {in[31:16], 16'h0100};
        3: padded_data = {in[31:8],   8'h01};
      endcase
endmodule
